sql:
SELECT season, SUM(total_rides) as total_rides_season FROM usage_trends
GROUP BY season
ORDER BY total_rides_season DESC;

SELECT SUM(total_rides) AS total_rides_sum
FROM usage_trends
WHERE season = 'Spring' AND year = 2017;

SELECT total_rides
FROM usage_trends
WHERE month = 6 AND year = 2017;

SELECT year, total_distance
FROM trip_statistics
WHERE total_distance = (
    SELECT MAX(total_distance)
    FROM trip_statistics
);

